// run.state === 'succeeded'. Three sub-cases on (child.state, run.prUrl):
// Use effectivePrUrl so that a successful reopenPr call on this tick can
// fall through directly to polling without waiting for the next tick.
let effectivePrUrl = run.prUrl;

if (child.state !== "pr_open") {
	// First observation. Decide pr_open vs trivial-merge.
	if (effectivePrUrl === null) {
		const trivial = await hasEmptyPushEvent(repos, child.runId);
		if (trivial) {
			const mergedAt = now().toISOString();
			await repos.planRuns.updateChild({
				planRunId: planRun.id,
				seq: child.seq,
				patch: { state: "merged", prMergedAt: mergedAt, endedAt: mergedAt },
				now: now(),
			});
			await emit(child.runId, "plan_run.merged", {
				planRunId: planRun.id,
				mergedChildSeq: child.seq,
				trivial: true,
			});
			return { kind: "merged" };
		}
		// Succeeded with no PR and no empty-push event вҖ” reap probably hit
		// a transient error before pr_open ran. Attempt to (re)open the PR
		// before failing terminally (warren-22de). The merge-wait budget
		// (mergeTimeoutMs, clock starts at run.endedAt) bounds the retry
		// window so the plan doesn't wait forever.
		if (mergeDeadlineExceeded(run.endedAt, now, mergeTimeoutMs)) {
			// Past budget вҖ” surface as terminal fail.
			const reason = "child_succeeded_without_pr";
			const endedAt = now().toISOString();
			await repos.planRuns.updateChild({
				planRunId: planRun.id,
				seq: child.seq,
				patch: { state: "failed", endedAt, failureReason: reason },
				now: now(),
			});
			await repos.planRuns.transitionTo(planRun.id, "failed", {
				endedAt,
				failureReason: reason,
			});
			await emit(child.runId, "plan_run.failed", {
				planRunId: planRun.id,
				failedSeq: child.seq,
				reason,
			});
			return {
				kind: "result",
				result: { kind: "plan_failed", failedSeq: child.seq, reason },
			};
		}
		// Within budget: attempt to (re)open the PR via the seam.
		if (reopenPr !== undefined) {
			const reopenedUrl = await reopenPr(run.id);
			if (reopenedUrl !== null) {
				// Persist so subsequent ticks see it via run.prUrl.
				await repos.runs.setPrUrl(run.id, reopenedUrl);
				effectivePrUrl = reopenedUrl;
				// Fall through to the pr_open flip + poll below.
			}
		}
		if (effectivePrUrl === null) {
			// No URL yet вҖ” emit a diagnostic event so the operator can see
			// the delay, and return noop so the next tick retries.
			await emit(child.runId, "plan_run.waiting_for_pr_reopen", {
				planRunId: planRun.id,
				seq: child.seq,
			});
			return {
				kind: "result",
				result: { kind: "noop", reason: `pr_reopen_pending:${run.id}` },
			};
		}
	}
	// Real PR (or reopened URL) вҖ” flip to pr_open and fall through to poll.
	await repos.planRuns.updateChild({
		planRunId: planRun.id,
		seq: child.seq,
		patch: { state: "pr_open" },
		now: now(),
	});
}

